83	  const dx = wall.end.xMm - wall.start.xMm;
84	  const dy = wall.end.yMm - wall.start.yMm;
85	  const lenSq = dx * dx + dy * dy;
86	  if (lenSq <= 1e-6) {
87	    return { point: wall.start, t: 0, distanceMm: distanceMm(point, wall.start) };
88	  }
89	  const rawT = ((point.xMm - wall.start.xMm) * dx + (point.yMm - wall.start.yMm) * dy) / lenSq;
90	  const t = Math.max(0, Math.min(1, rawT));
91	  const projected = {
92	    xMm: wall.start.xMm + dx * t,
93	    yMm: wall.start.yMm + dy * t,
94	  };
95	  return { point: projected, t, distanceMm: distanceMm(point, projected) };
96	}
