function makeJoin(
  kind: WallConnectivityJoinKind,
  point: { xMm: number; yMm: number },
  walls: WallConnectivityWall[],
  toleranceMm: number,
): WallConnectivityJoin {
  const wallIds = Array.from(new Set(walls.map((wall) => wall.id))).sort();
