export function wallConnectivityToPlanJoinRecords(
  joins: WallConnectivityJoin[],
  wallsById: Record<string, WallConnectivityWall>,
): WallPlanJoinRecord[] {
  const records: WallPlanJoinRecord[] = [];

  for (const join of joins) {
    for (let i = 0; i < join.wallIds.length; i += 1) {
      for (let j = i + 1; j < join.wallIds.length; j += 1) {
        const wallIdA = join.wallIds[i]!;
        const wallIdB = join.wallIds[j]!;
        const wallA = wallsById[wallIdA];
        const wallB = wallsById[wallIdB];
        if (!wallA || !wallB) continue;

        const disallowed =
          join.disallowedByWallId[wallIdA] === true || join.disallowedByWallId[wallIdB] === true;
        const aEndpoint = join.endpointByWallId[wallIdA];
        const bEndpoint = join.endpointByWallId[wallIdB];
        const joinKind: WallPlanJoinRecord['joinKind'] =
          join.kind === 't'
            ? 'butt'
            : join.kind === 'endpoint' && aEndpoint && bEndpoint && !isParallel(wallA, wallB)
              ? 'miter_candidate'
              : 'unsupported_skew';

        records.push({
          joinId: `${join.id}:plan:${wallIdA}:${wallIdB}`,
          wallIds: [wallIdA, wallIdB],
          vertexMm: join.point,
          levelId: join.levelId,
          joinKind,
          planDisplayToken: 'wall_join',
          affectedOpeningIds: [],
          skipReason: disallowed ? 'join_disallowed' : null,
        });
      }
    }
  }

  return records.sort((a, b) => a.joinId.localeCompare(b.joinId));
}

export function flipWallLocationLineSide(locationLine: WallLocationLine): WallLocationLine {
  switch (locationLine) {
    case 'finish-face-exterior':
      return 'finish-face-interior';
    case 'finish-face-interior':
      return 'finish-face-exterior';
    case 'core-face-exterior':
      return 'core-face-interior';
    case 'core-face-interior':
      return 'core-face-exterior';
    default:
      return locationLine;
  }
}

import type { ToolId, WorkspaceMode } from './toolRegistry';

export type AuthoringCommandKind =
  | 'line'
  | 'sketch'
  | 'hosted'
  | 'point'
  | 'modify'
  | 'review'
  | 'document'
  | 'resource';

export type AuthoringCompletionBehavior =
  | 'select-after-commit'
  | 'remain-active-while-looping'
  | 'explicit-finish'
  | 'stay-active'
  | 'selection-only'
  | 'opens-resource';

export interface AuthoringCommandContract {
  toolId: ToolId;
  kind: AuthoringCommandKind;
  validModes: WorkspaceMode[];
  requiredContext: string[];
  activeOptions: string[];
  previewSemantics: string;
  completionBehavior: AuthoringCompletionBehavior;
  defaultAfterCancel: 'select';
}

function contract(
  toolId: ToolId,
  kind: AuthoringCommandKind,
  validModes: WorkspaceMode[],
  previewSemantics: string,
  completionBehavior: AuthoringCompletionBehavior,
  requiredContext: string[] = [],
  activeOptions: string[] = [],
): AuthoringCommandContract {
  return {
    toolId,
    kind,
    validModes,
    requiredContext,
    activeOptions,
    previewSemantics,
    completionBehavior,
    defaultAfterCancel: 'select',
  };
}

