import type { Element } from '@bim-ai/core';

type WallElem = Extract<Element, { kind: 'wall' }>;
type FloorElem = Extract<Element, { kind: 'floor' }>;
type LevelElem = Extract<Element, { kind: 'level' }>;

export interface RoofByFootprintParams {
  footprintMm: { xMm: number; yMm: number }[];
  referenceLevelId: string;
  overhangMm: number;
  slopeDeg: number;
}

/** Signed area — positive = counterclockwise, negative = clockwise (screen coords). */
function signedArea(pts: { xMm: number; yMm: number }[]): number {
  let area = 0;
  const n = pts.length;
  for (let i = 0; i < n; i++) {
    const a = pts[i]!;
    const b = pts[(i + 1) % n]!;
    area += a.xMm * b.yMm - b.xMm * a.yMm;
  }
  return area / 2;
}

/** Expand a polygon outward by overhangMm in each vertex bisector direction. */
export function expandFootprintByOverhang(
  pts: { xMm: number; yMm: number }[],
  overhangMm: number,
): { xMm: number; yMm: number }[] {
  if (pts.length < 3 || overhangMm <= 0) return pts;
  const n = pts.length;
  // Determine winding: CCW = +1, CW = -1. Outward normals are CW of edge direction for CCW.
  const sign = signedArea(pts) >= 0 ? 1 : -1;
  return pts.map((p, i) => {
    const prev = pts[(i - 1 + n) % n]!;
    const next = pts[(i + 1) % n]!;
    const ex = p.xMm - prev.xMm;
    const ey = p.yMm - prev.yMm;
    const el = Math.hypot(ex, ey);
    // Outward normal of in-edge: perpendicular rotated by sign
    const nx1 = el > 1e-6 ? (sign * ey) / el : 0;
    const ny1 = el > 1e-6 ? (-sign * ex) / el : 0;
    const fx = next.xMm - p.xMm;
    const fy = next.yMm - p.yMm;
    const fl = Math.hypot(fx, fy);
    // Outward normal of out-edge
    const nx2 = fl > 1e-6 ? (sign * fy) / fl : 0;
    const ny2 = fl > 1e-6 ? (-sign * fx) / fl : 0;
    const bx = nx1 + nx2;
    const by = ny1 + ny2;
    const bl = Math.hypot(bx, by);
    const scale = bl > 1e-6 ? overhangMm / bl : overhangMm;
    return { xMm: p.xMm + bx * scale, yMm: p.yMm + by * scale };
  });
}

/** Derive a roof-by-footprint command payload from a closed wall loop or floor boundary. */
export function roofParamsFromWallLoop(
  walls: WallElem[],
  levelId: string,
  overhangMm: number,
  slopeDeg: number,
): RoofByFootprintParams | null {
  if (walls.length < 3) return null;
  const footprint: { xMm: number; yMm: number }[] = walls.map((w) => ({
    xMm: w.start.xMm,
    yMm: w.start.yMm,
  }));
  const expanded = expandFootprintByOverhang(footprint, overhangMm);
  return { footprintMm: expanded, referenceLevelId: levelId, overhangMm, slopeDeg };
}

/** Derive a roof-by-footprint command payload from a floor element boundary. */
export function roofParamsFromFloor(
  floor: FloorElem,
  overhangMm: number,
  slopeDeg: number,
): RoofByFootprintParams | null {
  const boundary = floor.boundaryMm ?? [];
  if (boundary.length < 3) return null;
  const expanded = expandFootprintByOverhang(boundary, overhangMm);
  return {
    footprintMm: expanded,
    referenceLevelId: floor.levelId,
    overhangMm,
    slopeDeg,
  };
}

/** Derive ceiling boundary from a room element or wall-enclosed area. */
export function ceilingBoundaryFromRoom(
  roomId: string,
  elementsById: Record<string, Element>,
): { xMm: number; yMm: number }[] | null {
  const room = elementsById[roomId];
  if (!room || room.kind !== 'room') return null;
  const r = room as Extract<Element, { kind: 'room' }>;
  const boundary = (r as unknown as { boundaryMm?: { xMm: number; yMm: number }[] }).boundaryMm;
  return boundary && boundary.length >= 3 ? boundary : null;
}

/** Validate that a shaft span is contiguous — it must not skip any levels between baseLevelId and topLevelId. */
export function validateShaftSpan(
  baseLevelId: string,
  topLevelId: string,
  elementsById: Record<string, Element>,
): { valid: boolean; reason: string | null } {
  const levels = Object.values(elementsById)
    .filter((e): e is LevelElem => e.kind === 'level')
    .sort((a, b) => (a.elevationMm ?? 0) - (b.elevationMm ?? 0));

  const baseIdx = levels.findIndex((l) => l.id === baseLevelId);
  const topIdx = levels.findIndex((l) => l.id === topLevelId);

  if (baseIdx === -1) return { valid: false, reason: 'base_level_not_found' };
  if (topIdx === -1) return { valid: false, reason: 'top_level_not_found' };
  if (baseIdx >= topIdx) return { valid: false, reason: 'base_level_not_below_top' };

  const baseElev = levels[baseIdx]!.elevationMm ?? 0;
  const topElev = levels[topIdx]!.elevationMm ?? 0;
  if (topElev <= baseElev) return { valid: false, reason: 'top_not_above_base' };

  return { valid: true, reason: null };
}

/** Build an attachWallTop command payload. */
export function buildAttachTopCommand(
  wallId: string,
  targetKind: 'roof' | 'floor' | 'level',
  targetId: string,
): Record<string, unknown> {
  return {
    type: 'attachWallTop',
    wallId,
    targetKind,
    targetId,
  };
}

/** Build a detachWallTop command payload. */
export function buildDetachTopCommand(wallId: string): Record<string, unknown> {
  return {
    type: 'detachWallTop',
    wallId,
  };
}

import { describe, expect, it } from 'vitest';

import type { Element } from '@bim-ai/core';

import {
  buildAttachTopCommand,
  buildDetachTopCommand,
  ceilingBoundaryFromRoom,
  expandFootprintByOverhang,
  roofParamsFromFloor,
  roofParamsFromWallLoop,
  validateShaftSpan,
} from './roofByFootprint';

type WallElem = Extract<Element, { kind: 'wall' }>;
type FloorElem = Extract<Element, { kind: 'floor' }>;

function makeWall(
  id: string,
  sx: number,
  sy: number,
  ex: number,
  ey: number,
  levelId = 'lvl-1',
): WallElem {
  return {
    kind: 'wall',
    id,
    levelId,
    start: { xMm: sx, yMm: sy },
    end: { xMm: ex, yMm: ey },
    heightMm: 3000,
  } as WallElem;
}

function makeFloor(id: string, boundary: { xMm: number; yMm: number }[]): FloorElem {
  return { kind: 'floor', id, levelId: 'lvl-1', boundaryMm: boundary } as FloorElem;
}

function makeLevel(id: string, elevationMm: number): Element {
  return { kind: 'level', id, name: id, elevationMm } as Element;
}

// ---------------------------------------------------------------------------
// WP-NEXT-45 — Roof by Footprint
// ---------------------------------------------------------------------------

describe('WP-NEXT-45 roofByFootprint', () => {
  describe('expandFootprintByOverhang', () => {
    it('expands a square by the given overhang on each side', () => {
      const pts = [
        { xMm: 0, yMm: 0 },
        { xMm: 4000, yMm: 0 },
        { xMm: 4000, yMm: 3000 },
        { xMm: 0, yMm: 3000 },
      ];
      const expanded = expandFootprintByOverhang(pts, 500);
      expect(expanded.length).toBe(4);
      // All points should be farther from the centroid than the originals.
      const cx = 2000;
      const cy = 1500;
      for (let i = 0; i < 4; i++) {
        const d0 = Math.hypot(pts[i]!.xMm - cx, pts[i]!.yMm - cy);
        const d1 = Math.hypot(expanded[i]!.xMm - cx, expanded[i]!.yMm - cy);
        expect(d1).toBeGreaterThan(d0 - 1);
      }
    });

    it('returns original points unchanged when overhang is 0', () => {
      const pts = [
        { xMm: 0, yMm: 0 },
        { xMm: 2000, yMm: 0 },
        { xMm: 2000, yMm: 2000 },
      ];
      expect(expandFootprintByOverhang(pts, 0)).toEqual(pts);
    });

    it('returns original points unchanged when fewer than 3 points', () => {
      const pts = [
        { xMm: 0, yMm: 0 },
        { xMm: 1000, yMm: 0 },
      ];
      expect(expandFootprintByOverhang(pts, 500)).toEqual(pts);
    });
  });

  describe('roofParamsFromWallLoop', () => {
    it('derives footprint from wall start points and expands by overhang', () => {
      const walls = [
        makeWall('s', 0, 0, 4000, 0),
        makeWall('e', 4000, 0, 4000, 3000),
        makeWall('n', 4000, 3000, 0, 3000),
        makeWall('w', 0, 3000, 0, 0),
      ];
      const params = roofParamsFromWallLoop(walls, 'lvl-1', 300, 25);
      expect(params).not.toBeNull();
      expect(params!.referenceLevelId).toBe('lvl-1');
      expect(params!.overhangMm).toBe(300);
      expect(params!.slopeDeg).toBe(25);
      expect(params!.footprintMm.length).toBe(4);
    });

    it('returns null for fewer than 3 walls', () => {
      const walls = [makeWall('a', 0, 0, 4000, 0), makeWall('b', 4000, 0, 4000, 3000)];
      expect(roofParamsFromWallLoop(walls, 'lvl-1', 0, 25)).toBeNull();
    });
  });

  describe('roofParamsFromFloor', () => {
    it('derives footprint from floor boundary', () => {
      const floor = makeFloor('f1', [
        { xMm: 0, yMm: 0 },
        { xMm: 5000, yMm: 0 },
        { xMm: 5000, yMm: 4000 },
        { xMm: 0, yMm: 4000 },
      ]);
      const params = roofParamsFromFloor(floor, 400, 30);
      expect(params).not.toBeNull();
      expect(params!.footprintMm.length).toBe(4);
      expect(params!.slopeDeg).toBe(30);
    });

    it('returns null when floor has no valid boundary', () => {
      const floor = makeFloor('f2', [
        { xMm: 0, yMm: 0 },
        { xMm: 1000, yMm: 0 },
      ]);
      expect(roofParamsFromFloor(floor, 0, 25)).toBeNull();
    });
  });

  describe('ceilingBoundaryFromRoom', () => {
    it('returns the room boundary when present', () => {
      const boundary = [
        { xMm: 0, yMm: 0 },
        { xMm: 3000, yMm: 0 },
        { xMm: 3000, yMm: 2000 },
        { xMm: 0, yMm: 2000 },
      ];
      const roomElem = {
        kind: 'room',
        id: 'rm-1',
        levelId: 'lvl-1',
        name: 'Living',
        boundaryMm: boundary,
      } as unknown as Element;
      const result = ceilingBoundaryFromRoom('rm-1', { 'rm-1': roomElem });
      expect(result).toEqual(boundary);
    });

    it('returns null when the room has no boundary', () => {
      const roomElem = { kind: 'room', id: 'rm-2', levelId: 'lvl-1', name: 'R' } as Element;
      expect(ceilingBoundaryFromRoom('rm-2', { 'rm-2': roomElem })).toBeNull();
    });

    it('returns null when the element id is not a room', () => {
      const wall = makeWall('w', 0, 0, 1000, 0);
      expect(ceilingBoundaryFromRoom('w', { w: wall as unknown as Element })).toBeNull();
    });
  });

  describe('validateShaftSpan', () => {
    const elementsById: Record<string, Element> = {
      'lvl-gnd': makeLevel('lvl-gnd', 0),
      'lvl-1': makeLevel('lvl-1', 3000),
      'lvl-2': makeLevel('lvl-2', 6000),
      'lvl-roof': makeLevel('lvl-roof', 9000),
    };

    it('accepts a valid two-level span', () => {
      const r = validateShaftSpan('lvl-gnd', 'lvl-2', elementsById);
      expect(r.valid).toBe(true);
      expect(r.reason).toBeNull();
    });

    it('rejects when base is not below top', () => {
      const r = validateShaftSpan('lvl-2', 'lvl-1', elementsById);
      expect(r.valid).toBe(false);
      expect(r.reason).toBe('base_level_not_below_top');
    });

    it('rejects when base level is unknown', () => {
      const r = validateShaftSpan('lvl-missing', 'lvl-2', elementsById);
      expect(r.valid).toBe(false);
      expect(r.reason).toBe('base_level_not_found');
    });

    it('rejects when top level is unknown', () => {
      const r = validateShaftSpan('lvl-gnd', 'lvl-missing', elementsById);
      expect(r.valid).toBe(false);
      expect(r.reason).toBe('top_level_not_found');
    });
  });

  describe('buildAttachTopCommand / buildDetachTopCommand', () => {
    it('builds an attachWallTop payload for a roof target', () => {
      const cmd = buildAttachTopCommand('wall-1', 'roof', 'roof-1');
      expect(cmd).toEqual({
        type: 'attachWallTop',
        wallId: 'wall-1',
        targetKind: 'roof',
        targetId: 'roof-1',
      });
    });

    it('builds a detachWallTop payload', () => {
      const cmd = buildDetachTopCommand('wall-1');
      expect(cmd).toEqual({ type: 'detachWallTop', wallId: 'wall-1' });
    });
  });
});

/**
 * View-tabs reducer — spec §11.3.
 *
 * Each tab is a pure descriptor of an open view: a `kind` (plan / 3d /
 * section / sheet / schedule) optionally tied to a
 * specific element id (a level for plan, a viewpoint for 3d, a section
 * cut for section, a sheet for sheet, a schedule for schedule).
 *
 * The reducer is framework-free so it can be unit-tested without React.
 */

import type { Element, LensMode } from '@bim-ai/core';

export type TabKind = 'plan' | '3d' | 'section' | 'sheet' | 'schedule';

/** Per-tab viewport state — restored when the tab is reactivated.
 * (T-07.) Plan tabs cache the 2D camera; 3D tabs cache the orbit pose.
 * Section / sheet / schedule tabs do not cache anything yet. */
export interface ViewportSnapshot {
  orbitCameraPoseMm?: {
    eyeMm?: { xMm: number; yMm: number; zMm: number };
    targetMm?: { xMm: number; yMm: number; zMm: number };
  };
  planCamera?: {
    centerMm?: { xMm: number; yMm: number };
    halfMm?: number;
  };
}

export interface ViewTab {
  /** Stable id. For target-bound tabs we use `${kind}:${targetId}` so
   * re-opening the same view activates the existing tab. */
  id: string;
  kind: TabKind;
  /** Element id this tab targets, when applicable. */
  targetId?: string;
  /** Display label — typically the element name with a kind prefix. */
  label: string;
  /** Cached camera/orbit state restored when the tab reactivates. */
  viewportState?: ViewportSnapshot;
  /** Discipline lens scoped to this tab instance. */
  lensMode?: LensMode;
}

export interface TabsState {
  tabs: ViewTab[];
  activeId: string | null;
}

export const EMPTY_TABS: TabsState = { tabs: [], activeId: null };

export function tabIdFor(kind: TabKind, targetId: string | undefined): string {
  return targetId ? `${kind}:${targetId}` : kind;
}

/** Open a tab — if one already exists for the same kind+target, just
 * activate it. Otherwise append a new tab. */
export function openTab(state: TabsState, partial: Omit<ViewTab, 'id'>): TabsState {
  const id = tabIdFor(partial.kind, partial.targetId);
  const existing = state.tabs.find((t) => t.id === id);
  if (existing) return { ...state, activeId: id };
  const tab: ViewTab = { id, kind: partial.kind, targetId: partial.targetId, label: partial.label };
  return { tabs: [...state.tabs, tab], activeId: id };
}

/** Close a tab. If it was the active one, activate the previous tab in
 * the list (or null if none remain). */
export function closeTab(state: TabsState, id: string): TabsState {
  const idx = state.tabs.findIndex((t) => t.id === id);
  if (idx === -1) return state;
  const next = state.tabs.filter((t) => t.id !== id);
  let nextActive = state.activeId;
  if (state.activeId === id) {
    if (next.length === 0) {
      nextActive = null;
    } else {
      // Activate the previous tab; if we closed the first, activate
      // the new first.
      const newIdx = Math.max(0, idx - 1);
      nextActive = next[newIdx]?.id ?? null;
    }
  }
  return { tabs: next, activeId: nextActive };
}

/** Keep only the active tab; close all others. */
export function closeInactiveTabs(state: TabsState): TabsState {
  if (!state.activeId) return state;
  const active = state.tabs.find((t) => t.id === state.activeId);
  if (!active) return state;
  return { tabs: [active], activeId: state.activeId };
}

/** Activate a tab by id. No-op if the id is unknown. */
export function activateTab(state: TabsState, id: string): TabsState {
  if (!state.tabs.some((t) => t.id === id)) return state;
  return { ...state, activeId: id };
}

/** Snapshot a tab's viewport state for later restore. (T-07.) Returns
 * the unchanged state if the id is unknown. */
export function snapshotViewport(
  state: TabsState,
  id: string,
  viewportState: ViewportSnapshot,
): TabsState {
  const idx = state.tabs.findIndex((t) => t.id === id);
  if (idx === -1) return state;
  const next = [...state.tabs];
  const existing = next[idx];
  if (!existing) return state;
  next[idx] = { ...existing, viewportState };
  return { ...state, tabs: next };
}

/** Reorder a tab from one index to another. Out-of-range indices clamp.
 * `activeId` is preserved (the active tab keeps focus, just at a new
 * position in the list). */
export function reorderTab(state: TabsState, fromIdx: number, toIdx: number): TabsState {
  if (state.tabs.length === 0) return state;
  const len = state.tabs.length;
  const f = Math.max(0, Math.min(len - 1, fromIdx));
  const t = Math.max(0, Math.min(len - 1, toIdx));
  if (f === t) return state;
  const next = [...state.tabs];
  const [moved] = next.splice(f, 1);
  if (!moved) return state;
  next.splice(t, 0, moved);
  return { ...state, tabs: next };
}

/** Cycle the active tab forward or backward. Wraps around. */
export function cycleActive(state: TabsState, direction: 'forward' | 'backward'): TabsState {
  if (state.tabs.length === 0) return state;
  const idx = state.activeId ? state.tabs.findIndex((t) => t.id === state.activeId) : -1;
  const len = state.tabs.length;
  const delta = direction === 'forward' ? 1 : -1;
  const nextIdx = ((((idx >= 0 ? idx : 0) + delta) % len) + len) % len;
  return { ...state, activeId: state.tabs[nextIdx]?.id ?? null };
}

/** Activate the first tab of `kind`, or open one with the given fallback
 * target if none exists. */
export function activateOrOpenKind(
  state: TabsState,
  kind: TabKind,
  fallback: Omit<ViewTab, 'id' | 'kind'>,
): TabsState {
  const existing = state.tabs.find((t) => t.kind === kind);
  if (existing) return { ...state, activeId: existing.id };
  return openTab(state, { kind, ...fallback });
}

/** Build a tab descriptor from an Element row. Returns `null` for kinds
 * that aren't directly viewable (walls, doors etc. — those are inspected
 * via the right rail, not opened as tabs). */
export function tabFromElement(el: Element): Omit<ViewTab, 'id'> | null {
  if (el.kind === 'level') {
    return { kind: 'plan', targetId: el.id, label: `Level plan · ${el.name}` };
  }
  if (el.kind === 'plan_view') {
    const subtype = (el as { planViewSubtype?: string }).planViewSubtype;
    const prefix =
      subtype === 'callout'
        ? 'Detail callout'
        : subtype === 'ceiling_plan'
          ? 'Ceiling plan'
          : 'Plan view';
    return { kind: 'plan', targetId: el.id, label: `${prefix} · ${el.name}` };
  }
  if (el.kind === 'viewpoint') {
    return { kind: '3d', targetId: el.id, label: `3D · ${el.name}` };
  }
  if (el.kind === 'saved_view') {
    return { kind: '3d', targetId: el.id, label: `3D · ${el.name}` };
  }
  if (el.kind === 'section_cut') {
    return { kind: 'section', targetId: el.id, label: `Section · ${el.name}` };
  }
  if (el.kind === 'sheet') {
    return { kind: 'sheet', targetId: el.id, label: `Sheet · ${el.name}` };
  }
  if (el.kind === 'schedule') {
    return { kind: 'schedule', targetId: el.id, label: `Schedule · ${el.name}` };
  }
  return null;
}

export const TAB_KIND_LABEL: Record<TabKind, string> = {
  plan: 'Plan',
  '3d': '3D',
  section: 'Section',
  sheet: 'Sheet',
  schedule: 'Schedule',
};

