export type ValidationSeverity = 'error' | 'warning';

export interface ValidationIssue {
  code: string;
  severity: ValidationSeverity;
  elementIds: string[];
  message: string;
}

type XY = { xMm: number; yMm: number };
type PolyBoundary = XY[];

// ---------------------------------------------------------------------------
// Polygon helpers
