148	function firstViewRefFromViewports(cmd: Record<string, unknown>): string | null {
149	  const rows = cmd.viewportsMm;
150	  if (!Array.isArray(rows) || !rows.length) return null;
151	  const first = rows[0];
152	  if (!first || typeof first !== 'object') return null;
153	  const vr =
154	    (first as Record<string, unknown>).viewRef ?? (first as Record<string, unknown>).view_ref;
155	  return typeof vr === 'string' && vr.trim() ? vr.trim() : null;
156	}
