158	/** One or two short monospace-friendly lines describing a pending quick-fix command. */
159	export function summarizeQuickFixCommand(cmd: Record<string, unknown>): string[] {
160	  const t = typeof cmd.type === 'string' ? cmd.type : '?';
161	  const lines: string[] = [`type: ${t}`];
162	
163	  if (typeof cmd.sheetId === 'string' && cmd.sheetId.trim()) {
164	    lines.push(`sheetId: ${cmd.sheetId.trim()}`);
165	  }
166	  if (typeof cmd.elementId === 'string' && cmd.elementId.trim()) {
167	    lines.push(`elementId: ${cmd.elementId.trim()}`);
168	  }
169	  if (typeof cmd.scheduleId === 'string' && cmd.scheduleId.trim()) {
170	    lines.push(`scheduleId: ${cmd.scheduleId.trim()}`);
171	  }
172	  if (typeof cmd.key === 'string' && cmd.key.trim()) {
173	    const key = cmd.key.trim();
174	    const val = cmd.value;
175	    const valStr =
176	      val === undefined || val === null
177	        ? ''
178	        : typeof val === 'string'
179	          ? JSON.stringify(val)
180	          : String(val);
181	    lines.push(valStr ? `property: ${key} → ${valStr}` : `property: ${key}`);
182	  }
183	
184	  const vr = firstViewRefFromViewports(cmd);
185	  if (vr) {
186	    lines.push(`first viewport viewRef: ${vr}`);
187	  }
188	
189	  return lines.slice(0, 4);
190	}
191	
192	const SEVERITY_RANK: Record<Violation['severity'], number> = {
193	  error: 0,
194	  warning: 1,
195	  info: 2,
196	};
197	
198	export function sortViolationsDeterministic(violations: Violation[]): Violation[] {
199	  return [...violations].sort((a, b) => {
200	    const ra = SEVERITY_RANK[a.severity] ?? 99;
201	    const rb = SEVERITY_RANK[b.severity] ?? 99;
202	    if (ra !== rb) return ra - rb;
203	    const idCmp = a.ruleId.localeCompare(b.ruleId);
204	    if (idCmp !== 0) return idCmp;
205	    return a.message.localeCompare(b.message);
206	  });
207	}
208	
209	export function groupViolationsBySeverity(
210	  sorted: Violation[],
211	): { severity: Violation['severity']; items: Violation[] }[] {
212	  const order: Violation['severity'][] = ['error', 'warning', 'info'];
213	  const buckets = new Map<Violation['severity'], Violation[]>();
214	  for (const sev of order) buckets.set(sev, []);
215	  for (const v of sorted) {
216	    const list = buckets.get(v.severity);
217	    if (list) list.push(v);
218	    else buckets.set(v.severity, [v]);
219	  }
220	  return order.flatMap((sev) => {
221	    const items = buckets.get(sev) ?? [];
222	    return items.length ? [{ severity: sev, items }] : [];
223	  });
224	}
