/**
 * Walk the line segments in order and produce an ordered polygon vertex list.
 * Returns null if the segments can't form a single closed loop.
 */
function orderedPolygonFromLines(
  lines: { fromMm: Point2D; toMm: Point2D }[],
  eps = 0.5,
): Point2D[] | null {
  if (lines.length < 3) return null;
  const key = (p: Point2D) => `${Math.round(p.xMm / eps)}|${Math.round(p.yMm / eps)}`;
  // Build adjacency: vertexKey → [connected endpoints]
  const adj = new Map<string, { pt: Point2D; neighbors: Point2D[] }>();
  for (const ln of lines) {
    for (const [a, b] of [
      [ln.fromMm, ln.toMm],
      [ln.toMm, ln.fromMm],
    ] as [Point2D, Point2D][]) {
      const ka = key(a);
      let entry = adj.get(ka);
      if (!entry) {
        entry = { pt: a, neighbors: [] };
        adj.set(ka, entry);
      }
      entry.neighbors.push(b);
    }
  }
  // Walk the polygon starting from the first vertex
  const start = [...adj.values()][0]!;
  const visited = new Set<string>();
  const polygon: Point2D[] = [start.pt];
  visited.add(key(start.pt));
  let current = start;
  for (let i = 1; i < lines.length; i++) {
    const next = current.neighbors.find((n) => !visited.has(key(n)));
    if (!next) return null;
    polygon.push(next);
    visited.add(key(next));
    current = adj.get(key(next))!;
    if (!current) return null;
  }
  return polygon;
}

