90	function snapMm(p: Point2D, snapMmGrid: number): Point2D {
91	  return {
92	    xMm: Math.round(p.xMm / snapMmGrid) * snapMmGrid,
93	    yMm: Math.round(p.yMm / snapMmGrid) * snapMmGrid,
94	  };
