101	/** Vertices that have ≠ 2 incident edges → highlighted red in the canvas. */
102	function openVerticesForLines(lines: { fromMm: Point2D; toMm: Point2D }[]): Point2D[] {
103	  const incidence = new Map<string, { pt: Point2D; count: number }>();
104	  for (const ln of lines) {
105	    for (const pt of [ln.fromMm, ln.toMm]) {
106	      const k = _vertexKey(pt);
107	      const cur = incidence.get(k);
108	      if (cur) cur.count += 1;
109	      else incidence.set(k, { pt, count: 1 });
110	    }
111	  }
112	  return [...incidence.values()].filter((v) => v.count !== 2).map((v) => v.pt);
113	}
