115	/**
116	 * SKT-03: detect a single missing closing segment between two unique open
117	 * endpoints. When exactly two open vertices exist, "Auto-close" can connect
118	 * them with one extra sketch line.
119	 */
120	function autoCloseCandidate(
121	  lines: { fromMm: Point2D; toMm: Point2D }[],
122	): [Point2D, Point2D] | null {
123	  const opens = openVerticesForLines(lines);
124	  if (opens.length !== 2) return null;
125	  return [opens[0]!, opens[1]!];
126	}
